Web Forms (Before)Blazor (After) <pre><code>protected void Page_Load(object sender, EventArgs e)
{
    if (!IsPostBack)
    {
        Page.ClientScript.RegisterStartupScript(
            this.GetType(),
            "InitializeUI",
            "$(function() { applyTheme('dark'); });",
            addScriptTags: true);
    }
}
</code></pre> <pre><code>@inject IJSRuntime JS

@code {
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            var module = await JS.InvokeAsync&lt;IJSObjectReference&gt;(
                "import", "./app.js");
            await module.InvokeVoidAsync("applyTheme", "dark");
        }
    }
}
</code></pre>

