Web Forms (Before)Blazor (After) <pre><code>public partial class MyControl : UserControl, IPostBackEventHandler
{
    public event EventHandler&lt;ItemSelectedEventArgs&gt; OnItemSelected;

    public void RaisePostBackEvent(string eventArgument)
    {
        if (eventArgument.StartsWith("select-"))
        {
            string itemId = eventArgument.Substring("select-".Length);
            OnItemSelected?.Invoke(this, new ItemSelectedEventArgs { ItemId = itemId });
        }
    }
}

public class ItemSelectedEventArgs : EventArgs
{
    public string ItemId { get; set; }
}
</code></pre> <pre><code>@* MyControl.razor *@

@foreach (var item in Items)
{
